def encrypt(s):
    result = []
    for char in s:
        if char.isalpha():
            # Determine if uppercase or lowercase
            if char.isupper():
                # Shift uppercase letters by 4 (2 * 2)
                shifted = chr((ord(char) - ord('A') + 4) % 26 + ord('A'))
            else:
                # Shift lowercase letters by 4 (2 * 2)
                shifted = chr((ord(char) - ord('a') + 4) % 26 + ord('a'))
            result.append(shifted)
        else:
            # Keep non-alphabetic characters as is
            result.append(char)
    return ''.join(result)
